 49→const formatTimeAgo = (date) => {
 50→    if (!date) return '';
 51→    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
 52→    if (seconds < 60) return 'just now';
 53→    const minutes = Math.floor(seconds / 60);
 54→    if (minutes < 60) return `${minutes}m ago`;
