 59→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
 60→    const [editor] = useLexicalComposerContext();
