 90→    // Tick the "saved X ago" display every 30s
 91→    useEffect(() => {
 92→        if (!lastSavedAt) return;
 93→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 94→        return () => clearInterval(interval);
 95→    }, [lastSavedAt]);
 96→
 97→    const invalidateCreatedJournalQueries = useCallback(async() => {
 98→        const invalidations = [
 99→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
100→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
101→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
102→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
103→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
104→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
105→        ];
106→
107→        if(userId){
108→            invalidations.push(
109→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
110→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
111→            );
112→        }
113→
114→        await Promise.allSettled(invalidations);
115→    }, [queryClient, userId]);
116→
117→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
118→        if (!editorState || !session?.access_token) return;
119→        if (showFeedback) setSaveStatus('saving');
120→
121→        try {
122→            const result = await saveDraft(session.access_token, {
123→                content: editorState,
124→                title: title || '',
