                <div className="toolbar-color-picker">
                    <button
                        type="button"
                        onMouseDown={(e) => e.preventDefault()}
                        onClick={() => {
                            setShowTextColorPicker((prev) => !prev);
                            setShowHighlightColorPicker(false);
                        }}
                        className="toolbar-color-trigger"
                        title="Text color"
                        aria-label="Text color"
                    >
