    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
    padding: 4px 6px;
    gap: 4px;
    max-width: 380px;
}
.floating-link-edit-row,
.floating-link-display-row {
    display: flex;
    align-items: center;
    gap: 4px;
}
.floating-link-input {
    border: 1px solid var(--border-light, #e0e0e0);
    border-radius: 4px;
    padding: 4px 8px;
    font-size: 0.8rem;
    width: 200px;
    background: transparent;
    color: var(--text-primary);
    outline: none;
}
.floating-link-input:focus {
    border-color: var(--editor-accent, var(--accent-purple));
}
.floating-link-url {
    font-size: 0.8rem;
    color: var(--editor-accent, var(--accent-purple));
    text-decoration: none;
    max-width: 200px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}
.floating-link-url:hover {
    text-decoration: underline;
}
.floating-link-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 4px;
    border: none;
    background: transparent;
    border-radius: 4px;
    cursor: pointer;
    color: var(--text-secondary, #666);
    transition: background-color 0.1s;
}
.floating-link-btn:hover {
    background-color: var(--bg-pill, rgba(0, 0, 0, 0.06));
}
.floating-link-save {
    color: var(--editor-accent, var(--accent-purple));
}
.floating-link-remove {
    color: #d73a49;
}

/* ── Floating selection toolbar ── */
.floating-selection-toolbar {
    position: absolute;
    z-index: 600;
    display: flex;
    align-items: center;
    gap: 2px;
    background: var(--bg-elevated, #fff);
    border: 1px solid var(--border-light, #e0e0e0);
    border-radius: 8px;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
    padding: 3px 4px;
}
.fst-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 5px;
    border: none;
    background: transparent;
    border-radius: 5px;
    cursor: pointer;
    color: var(--text-primary, #333);
    transition: background-color 0.1s;
}
.fst-btn:hover {
    background-color: var(--bg-pill, rgba(0, 0, 0, 0.06));
}
.fst-active {
    background-color: color-mix(in srgb, var(--editor-accent, var(--accent-purple)) 15%, transparent);
    color: var(--editor-accent, var(--accent-purple));
}
.fst-active svg {
    fill: var(--editor-accent, var(--accent-purple));
}
.fst-divider {
    width: 1px;
    height: 16px;
    background-color: var(--border-light, #e0e0e0);
    margin: 0 2px;
}

/* ── Mobile responsive (overrides only) ── */
@media (max-width: 640px) {
    .editor-parent-container {
        z-index: 132;
    }
    .editor-container {
        width: 95%;
        height: 95%;
        padding: 0.75rem;
        border-radius: 12px;
    }
    /* Mobile toolbar: horizontal scroll with visible thin scrollbar */
    .toolbar {
        flex-wrap: nowrap;
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        scrollbar-width: thin;
        min-width: 0;
    }
    .toolbar .group,
    .toolbar .toolbar-bttns,
    .toolbar .is-active {
        flex-shrink: 0;
    }
    .toolbar::-webkit-scrollbar {
        height: 3px;
    }
    .toolbar::-webkit-scrollbar-thumb {
        background: var(--editor-border);
        border-radius: 3px;
    }
    .toolbar-wrapper {
        position: relative;
    }
    .toolbar-wrapper::after {
        content: '';
        position: absolute;
        top: 0;
        right: 0;
        bottom: 0;
        width: 24px;
        background: linear-gradient(to right, transparent, var(--editor-bg, var(--bg-elevated)));
        pointer-events: none;
        z-index: 6;
    }
    .toolbar-bttns,
    .is-active {
        padding: 0.55rem;
        min-width: 36px;
        min-height: 36px;
    }
    .toolbar-bttns svg,
    .is-active svg {
        width: 18px;
        height: 18px;
    }
    .toolbar-divider {
        margin: 0 4px;
        height: 16px;
    }
    .color-popover {
        bottom: calc(100% + 6px);
        top: auto;
    }
    .content-title-input {
        font-size: 1.35rem;
    }
    .editor-save-bttn {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-save-bttn-disabled {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-draft-bttn {
        padding: 0.35rem 0.75rem;
        font-size: 0.8rem;
    }
    .editor-draft-bttn-disabled {
        padding: 0.35rem 0.75rem;
        font-size: 0.8rem;
    }
    .editor-footer-actions {
        gap: 0.35rem;
    }
    .editor-close-confirm-overlay {
        border-radius: 12px;
    }
    .editor-close-confirm-card {
        padding: 1.25rem 1.5rem;
        max-width: 280px;
    }
}

