 59→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
 60→    const [editor] = useLexicalComposerContext();
 61→    const [editorState, setEditorState] = useState(null);
 62→    const [hasContent, setHasContent] = useState(false);
 63→    const [isSending, setIsSending] = useState(false);
 64→
 65→    // Draft state
 66→    const draftIdRef = useRef(draftId);
 67→    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
 68→    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
 69→    const [hasChanges, setHasChanges] = useState(false);
 70→    const saveTimerRef = useRef(null);
 71→    const [, forceUpdate] = useState(0);
 72→
 73→    // Expose saveTimerRef to parent so it can cancel pending auto-saves
 74→    useEffect(() => {
 75→        if (editorStateRef) {
 76→            editorStateRef.current.saveTimerRef = saveTimerRef;
 77→        }
 78→    }, [editorStateRef]);
 79→
 80→    const {session, user} = useAuth();
 81→
 82→    const queryClient = useQueryClient();
 83→    const userId = user?.userData?.[0]?.id || null;
 84→
 85→    // Keep draftIdRef in sync
 86→    useEffect(() => {
 87→        draftIdRef.current = draftId;
 88→    }, [draftId]);
 89→
 90→    // Tick the "saved X ago" display every 30s
 91→    useEffect(() => {
 92→        if (!lastSavedAt) return;
 93→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 94→        return () => clearInterval(interval);
 95→    }, [lastSavedAt]);
 96→
 97→    const invalidateCreatedJournalQueries = useCallback(async() => {
 98→        const invalidations = [
 99→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
100→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
101→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
102→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
103→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
104→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
105→        ];
106→
107→        if(userId){
108→            invalidations.push(
109→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
110→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
111→            );
112→        }
113→
114→        await Promise.allSettled(invalidations);
115→    }, [queryClient, userId]);
116→
117→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
118→        if (!editorState || !session?.access_token) return;
119→        if (showFeedback) setSaveStatus('saving');
120→
121→        try {
122→            const result = await saveDraft(session.access_token, {
123→                content: editorState,
124→                title: title || '',
125→                draftId: draftIdRef.current || null,
126→                prompt_id: promptId || null,
127→            });
128→
129→            if (result?.id && !draftIdRef.current) {
130→                draftIdRef.current = result.id;
131→                if (onDraftIdCreated) onDraftIdCreated(result.id);
132→            }
133→
134→            setHasChanges(false);
135→            setSaveStatus('saved');
136→            setLastSavedAt(new Date());
137→            if (editorStateRef) {
138→                editorStateRef.current = { ...editorStateRef.current, hasChanges: false };
139→            }
140→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
141→        } catch (error) {
142→            console.error('Failed to save draft:', error);
143→            setSaveStatus('unsaved');
144→        }
145→    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);
146→
147→    // Auto-save every 30 seconds when there are changes
148→    useEffect(() => {
149→        if (!hasChanges || !editorState) return;
150→
151→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
152→        saveTimerRef.current = setTimeout(() => {
153→            handleSaveDraft(false);
154→        }, 30000);
155→
156→        return () => {
157→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
158→        };
159→    }, [editorState, hasChanges, handleSaveDraft]);
160→
161→    const handleClickPublish = async(e, title) => {
162→        e.stopPropagation();
163→        setIsSending(true);
164→
165→        try {
166→            // If we have a draft, publish it
167→            if (draftIdRef.current) {
168→                // Save latest content first
169→                await saveDraft(session.access_token, {
170→                    content: editorState,
171→                    title: title || '',
172→                    draftId: draftIdRef.current,
173→                });
174→
175→                await publishDraft(session.access_token, draftIdRef.current);
176→            } else {
177→                // Direct publish (no draft exists) — use existing save-journal flow
178→                const formdata = new FormData();
179→                if(title && editorState){
180→                    formdata.append('title', title);
181→                    formdata.append('content', editorState);
182→                }
183→                if(promptId){
184→                    formdata.append('prompt_id', promptId);
185→                }
186→                await saveJournal(session?.access_token, formdata);
187→            }
188→
189→            await invalidateCreatedJournalQueries();
190→            setHasContent(false);
191→            onCloseOnSave();
192→            addUploadImagesPath([]);
193→        } catch (error) {
194→            console.error("Error publishing journal:", error);
195→        } finally {
196→            setIsSending(false);
197→        }
198→    }
199→
200→    const onchange = useCallback((state) => {
201→        const jsonb = JSON.stringify(state.toJSON());
202→        setEditorState(jsonb)
203→        setHasChanges(true);
204→        if (saveStatus === 'saved') setSaveStatus('unsaved');
205→
206→        state.read(() => {
207→            const root = $getRoot();
208→
209→            const children = root.getChildren();
210→
211→            const hasEnoughParagraphNodes = children.length > 1
212→            const hasParargraphSize = children[0]?.__size > 0
213→
214→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
215→            setHasContent(hasContent);
216→
217→            // Calculate word count
218→            const text = root.getTextContent().trim();
219→            const words = text ? text.split(/\s+/).length : 0;
220→            setWordCount(words);
221→
222→            // Expose state to parent via ref
223→            if (editorStateRef) {
224→                editorStateRef.current = { ...editorStateRef.current, hasChanges: true, hasContent, editorState: jsonb, title };
225→            }
226→        })
227→    }, [setWordCount, saveStatus])
228→
229→    const renderSaveStatus = () => {
230→        if (!saveStatus) return null;
231→
232→        let statusText = '';
233→        let statusClass = 'editor-save-status';
234→
235→        switch (saveStatus) {
236→            case 'saving':
237→                statusText = 'Saving...';
238→                statusClass += ' editor-save-status--saving';
239→                break;
240→            case 'saved':
241→                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
242→                statusClass += ' editor-save-status--saved';
243→                break;
244→            case 'unsaved':
245→                statusText = 'Unsaved changes';
246→                statusClass += ' editor-save-status--unsaved';
247→                break;
248→            default:
249→                return null;
250→        }
251→
252→        return <span className={statusClass}>{statusText}</span>;
253→    };
254→
255→    return(
256→        <>
257→        {/* Bar loader directly under toolbar */}
258→        <div className="editor-loader-wrapper">
259→            {isSending && (
260→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
261→            )}
262→        </div>
263→
264→        {/* Editor content area */}
265→        <div className="editor-shell">
266→            <RichTextPlugin
267→            contentEditable={
268→            <ContentEditable
269→            className="editor-input"
270→            aria-placeholder="Write your thoughts here..."
271→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
272→            }
273→            ErrorBoundary={LexicalErrorBoundary}
274→            />
275→
276→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
277→            <MentionPlugin/>
278→            <HistoryPlugin/>
279→            <OnChangePlugin onChange={onchange}/>
280→            <ListPlugin/>
281→            <CheckListPlugin/>
282→            <HorizontalRulePlugin/>
283→            <LinkPlugin validateUrl={(url) => {
284→                try { return Boolean(new URL(url)); } catch { return false; }
285→            }}/>
286→            <AutoLinkPlugin/>
287→            <CodeHighlightPlugin/>
288→            <MarkdownShortcutPlugin transformers={TRANSFORMERS}/>
289→            <FloatingLinkEditor/>
290→            <FloatingSelectionToolbar/>
291→            <PasteImagePlugin addUploadedImagePath={addUploadImagesPath} token={session?.access_token}/>
292→
293→        </div>
294→
295→        {/* Footer: word count + save status + buttons */}
296→        <div className='editor-footer'>
297→            <div className="editor-footer-left">
298→                <span className="editor-word-count">
299→                    {wordCount} {wordCount === 1 ? 'word' : 'words'}
300→                </span>
301→                {renderSaveStatus()}
302→            </div>
303→            <div className="editor-footer-actions">
304→                <button
305→                    disabled={!hasContent || isSending}
306→                    onClick={() => handleSaveDraft(true)}
307→                    className={hasContent && !isSending ? 'editor-draft-bttn' : 'editor-draft-bttn-disabled'}
308→                >
309→                    Save Draft
310→                </button>
311→                <button
312→                    disabled={!title || !hasContent || isSending}
313→                    onClick={(e) => handleClickPublish(e, title)}
314→                    className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}
315→                >
316→                    Publish
317→                </button>
318→            </div>
319→        </div>
320→        </>
321→    )
322→}
323→
324→export default EditorInner;
