 27→const DEFAULT_ACTIVE_STATES = {
 28→    bold: false,
 29→    italic: false,
 30→    underline: false,
 31→    strikethrough: false,
 32→    inlineCode: false,
 33→    heading: null,
 34→    quote: false,
