 45→const ToolBar = ({addUploadedImagePath}) =>{
 46→    const [editor] = useLexicalComposerContext();
 47→    const {session} = useAuth();
 48→    const colorPickerRef = useRef(null);
 49→
 50→    // Active state tracking
 51→    const [activeStates, setActiveStates] = useState(DEFAULT_ACTIVE_STATES);
 52→
 53→    const [showTextColorPicker, setShowTextColorPicker] = useState(false);
 54→    const [showHighlightColorPicker, setShowHighlightColorPicker] = useState(false);
 55→
 56→    const COLOR_PALETTE = [
 57→        { label: 'Default', value: null },
 58→        { label: 'Black', value: '#000000' },
 59→        { label: 'Dark Gray', value: '#4d4d4d' },
 60→        { label: 'Gray', value: '#888888' },
 61→        { label: 'Light Gray', value: '#bfbfbf' },
 62→        { label: 'Red', value: '#f44336' },
 63→        { label: 'Pink', value: '#e91e63' },
 64→        { label: 'Purple', value: '#9c27b0' },
 65→        { label: 'Deep Purple', value: '#673ab7' },
 66→        { label: 'Indigo', value: '#3f51b5' },
 67→        { label: 'Blue', value: '#2196f3' },
 68→        { label: 'Light Blue', value: '#03a9f4' },
 69→        { label: 'Cyan', value: '#00bcd4' },
 70→        { label: 'Teal', value: '#009688' },
 71→        { label: 'Green', value: '#4caf50' },
 72→        { label: 'Light Green', value: '#8bc34a' },
 73→        { label: 'Lime', value: '#cddc39' },
 74→        { label: 'Yellow', value: '#ffeb3b' },
 75→        { label: 'Amber', value: '#ffc107' },
 76→        { label: 'Orange', value: '#ff9800' },
 77→        { label: 'Deep Orange', value: '#ff5722' },
 78→        { label: 'Brown', value: '#795548' },
 79→        { label: 'Blue Gray', value: '#607d8b' },
 80→    ];
 81→
 82→    const toCompactRgb = (value) => {
 83→        if (!value) return '';
 84→        return value.toLowerCase().replace(/\s+/g, '');
 85→    };
 86→
 87→    const normalizeColor = (value) => {
 88→        if (!value) return '';
 89→        const trimmed = value.trim().toLowerCase();
 90→        if (!trimmed.startsWith('#')) {
 91→            return toCompactRgb(trimmed);
 92→        }
 93→
 94→        let hex = trimmed.slice(1);
 95→        if (hex.length === 3) {
 96→            hex = hex.split('').map((char) => `${char}${char}`).join('');
 97→        }
 98→        if (hex.length !== 6) {
 99→            return trimmed;
100→        }
101→
102→        const r = parseInt(hex.slice(0, 2), 16);
103→        const g = parseInt(hex.slice(2, 4), 16);
104→        const b = parseInt(hex.slice(4, 6), 16);
105→
106→        return `rgb(${r},${g},${b})`;
107→    };
108→
109→    const isPaletteColorActive = (activeValue, paletteValue) => {
110→        const normalizedActive = normalizeColor(activeValue);
111→        if (!paletteValue) {
112→            return !normalizedActive;
113→        }
114→        return normalizedActive === normalizeColor(paletteValue);
115→    };
116→
117→    // Register undo/redo command listeners
118→    useEffect(() => {
119→        const unregisterUndo = editor.registerCommand(
120→            CAN_UNDO_COMMAND,
121→            (payload) => {
122→                setActiveStates((prev) => ({ ...prev, canUndo: payload }));
123→                return false;
124→            },
125→            COMMAND_PRIORITY_LOW,
126→        );
127→        const unregisterRedo = editor.registerCommand(
128→            CAN_REDO_COMMAND,
129→            (payload) => {
130→                setActiveStates((prev) => ({ ...prev, canRedo: payload }));
131→                return false;
132→            },
133→            COMMAND_PRIORITY_LOW,
134→        );
135→        return () => {
136→            unregisterUndo();
137→            unregisterRedo();
138→        };
139→    }, [editor]);
140→
141→    // Register update listener for active state detection
142→    useEffect(() => {
143→        return editor.registerUpdateListener(({ editorState }) => {
144→            editorState.read(() => {
145→                const selection = $getSelection();
146→                if (!$isRangeSelection(selection)) {
147→                    setActiveStates((prev) => ({
148→                        ...DEFAULT_ACTIVE_STATES,
149→                        canUndo: prev.canUndo,
150→                        canRedo: prev.canRedo,
151→                    }));
152→                    return;
153→                }
154→
155→                const bold = selection.hasFormat('bold');
156→                const italic = selection.hasFormat('italic');
157→                const underline = selection.hasFormat('underline');
158→                const strikethrough = selection.hasFormat('strikethrough');
159→                const inlineCode = selection.hasFormat('code');
160→
161→                const anchorNode = selection.anchor.getNode();
162→                const parent = anchorNode.getParent();
163→
164→                let element;
165→                try {
166→                    element = anchorNode.getKey() === 'root'
167→                        ? anchorNode
168→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
169→                } catch {
170→                    element = null;
171→                }
172→
173→                let heading = null;
174→                let quote = false;
175→                let alignment = 'left';
176→                let listType = null;
177→                let isCodeBlock = false;
178→                let isLink = false;
179→
180→                if (element) {
181→                    if ($isHeadingNode(element)) {
182→                        heading = element.getTag();
183→                    }
184→                    if ($isQuoteNode(element)) {
185→                        quote = true;
186→                    }
187→                    if ($isListNode(element)) {
188→                        const type = element.getListType();
189→                        listType = type === 'bullet' ? 'bullet' : type === 'number' ? 'number' : type === 'check' ? 'check' : null;
190→                    }
191→                    if ($isCodeNode(element)) {
192→                        isCodeBlock = true;
193→                    }
194→                    const formatType = element.getFormatType?.();
195→                    if (formatType) {
196→                        alignment = formatType;
197→                    }
198→                }
199→
200→                // Check for list type on parent (listitem → list)
201→                if (!listType && parent) {
202→                    const grandParent = parent.getParent?.();
203→                    if (grandParent && $isListNode(grandParent)) {
204→                        const type = grandParent.getListType();
205→                        listType = type === 'bullet' ? 'bullet' : type === 'number' ? 'number' : type === 'check' ? 'check' : null;
206→                    }
207→                }
208→
209→                // Check for link
210→                if ($isLinkNode(parent)) {
211→                    isLink = true;
212→                } else if ($isLinkNode(anchorNode)) {
213→                    isLink = true;
214→                }
215→
216→                const textColor = $getSelectionStyleValueForProperty(selection, 'color', '');
217→                const highlightColor = $getSelectionStyleValueForProperty(selection, 'background-color', '');
218→
219→                setActiveStates((prev) => ({
220→                    bold,
221→                    italic,
222→                    underline,
223→                    strikethrough,
224→                    inlineCode,
225→                    heading,
226→                    quote,
227→                    alignment,
228→                    textColor,
229→                    highlightColor,
230→                    listType,
231→                    isCodeBlock,
232→                    isLink,
233→                    canUndo: prev.canUndo,
234→                    canRedo: prev.canRedo,
235→                }));
236→            });
237→        });
