582→                </div>
583→
584→                <div className="toolbar-color-picker">
585→                    <button
586→                        type="button"
587→                        onMouseDown={(e) => e.preventDefault()}
588→                        onClick={() => {
589→                            setShowHighlightColorPicker((prev) => !prev);
590→                            setShowTextColorPicker(false);
591→                        }}
592→                        className="toolbar-color-trigger"
593→                        title="Highlight"
594→                        aria-label="Highlight"
595→                    >
596→                        <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor">
597→                            <path d="m320-240 60-120 160 160-120 60-100-100ZM560-400l-240-240 60-60 240 240-60 60ZM660-300l-60-60 160-160 60 60-160 160ZM200-80v-80h560v80H200Zm500-580-60-60 60-60 60 60-60 60Z"/>
598→                        </svg>
599→                        <span
600→                            className="toolbar-color-swatch"
601→                            style={{ backgroundColor: activeStates.highlightColor || 'transparent' }}
602→                        />
603→                    </button>
604→                    {showHighlightColorPicker && (
605→                        <div className="color-popover" onMouseDown={(e) => e.preventDefault()}>
606→                            {COLOR_PALETTE.map((color) => {
607→                                const isActive = isPaletteColorActive(activeStates.highlightColor, color.value);
608→                                const swatchClass = color.value
609→                                    ? 'color-swatch'
610→                                    : 'color-swatch is-default';
611→                                return (
612→                                    <button
613→                                        key={`highlight-${color.label}`}
614→                                        type="button"
615→                                        className={isActive ? `${swatchClass} is-selected` : swatchClass}
616→                                        title={color.label}
617→                                        aria-label={`Highlight color ${color.label}`}
618→                                        onClick={() => {
619→                                            applyTextStyle({ 'background-color': color.value });
620→                                            setShowHighlightColorPicker(false);
621→                                        }}
622→                                        style={{ backgroundColor: color.value || 'transparent' }}
623→                                    />
624→                                );
625→                            })}
626→                        </div>
627→                    )}
628→                </div>
629→            </div>
630→
631→            <div className="toolbar-divider" />
632→
633→            {/* Group 8: Alignment */}
634→            <div className="group">
635→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => setAlignment('left')} className={getBtnClass(activeStates.alignment === 'left' || activeStates.alignment === '')} title="Align left">
636→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M120-120v-80h720v80H120Zm0-160v-80h480v80H120Zm0-160v-80h720v80H120Zm0-160v-80h480v80H120Zm0-160v-80h720v80H120Z"/></svg>
637→                </div>
638→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => setAlignment('center')} className={getBtnClass(activeStates.alignment === 'center')} title="Align center">
639→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M120-120v-80h720v80H120Zm160-160v-80h400v80H280ZM120-440v-80h720v80H120Zm160-160v-80h400v80H280ZM120-760v-80h720v80H120Z"/></svg>
640→                </div>
641→                <div onMouseDown={(e) => e.preventDefault()} onClick={() => setAlignment('right')} className={getBtnClass(activeStates.alignment === 'right')} title="Align right">
642→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M120-760v-80h720v80H120Zm240 160v-80h480v80H360ZM120-440v-80h720v80H120Zm240 160v-80h480v80H360ZM120-120v-80h720v80H120Z"/></svg>
643→                </div>
644→            </div>
645→        </div>
646→    )
647→}
648→export default ToolBar;
