  8→const ResizableImageComponent = ({ src ,nodeKey, width, height, loading = false, rotation = 0, isEditable = true }) => {
  9→  const [editor] = useLexicalComposerContext();
 10→  const [isResizing, setIsResizing] = useState(false);
 11→  const [currentWidth, setCurrentWidth] = useState(width);
 12→  const [currentHeight, setCurrentHeight] = useState(height);
 13→  const [currentRotation, setCurrentRotation] = useState(rotation);
 14→  const [isSelected, setIsSelected] = useState(false);
