import React, { useCallback, useEffect, useRef, useState } from "react";
import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
import { ContentEditable } from "@lexical/react/LexicalContentEditable";
import { HistoryPlugin } from "@lexical/react/LexicalHistoryPlugin";
import { OnChangePlugin } from "@lexical/react/LexicalOnChangePlugin";
import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
import { ListPlugin } from "@lexical/react/LexicalListPlugin";
import { CheckListPlugin } from "@lexical/react/LexicalCheckListPlugin";
import { HorizontalRulePlugin } from "@lexical/react/LexicalHorizontalRulePlugin";
import { LinkPlugin } from "@lexical/react/LexicalLinkPlugin";
import { MarkdownShortcutPlugin } from "@lexical/react/LexicalMarkdownShortcutPlugin";
import { TRANSFORMERS } from "@lexical/markdown";
import { CodeHighlightPlugin } from "./plugins/CodeHighlightPlugin";
import { AutoLinkPlugin } from "./plugins/AutoLinkPlugin";
import FloatingLinkEditor from "./plugins/FloatingLinkEditor";
import FloatingSelectionToolbar from "./plugins/FloatingSelectionToolbar";
import PasteImagePlugin from "./plugins/PasteImagePlugin";
import ImagePlugin from "./nodes/Plugins/ImagePlugin";
import MentionPlugin from "./nodes/Plugins/MentionPlugin";

import { saveJournal, saveDraft, publishDraft } from "../../../../API/Api";
import { useAuth } from "../../../Context/useAuth";
import { useQueryClient } from '@tanstack/react-query';

import { BarLoader } from "react-spinners";
import { $getRoot } from "lexical";


class ErrorBoundary extends React.Component {
  state = { error: null };
  static getDerivedStateFromError(error) {
    return { error };
  }
  render() {
    if (this.state.error) {
      return <div>Error: {this.state.error.message}</div>;
    }
    return this.props.children;
  }
}

/* theme for mapping css classes to lexical rols */
const theme = {
    paragraph: 'editor-paragraph',
    heading: 'editor-heading',
}

const formatTimeAgo = (date) => {
    if (!date) return '';
    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
    if (seconds < 60) return 'just now';
    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes}m ago`;
    const hours = Math.floor(minutes / 60);
    return `${hours}h ago`;
};

const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated, editorStateRef}) => {
    const [editor] = useLexicalComposerContext();
    const [editorState, setEditorState] = useState(null);
    const [hasContent, setHasContent] = useState(false);
    const [isSending, setIsSending] = useState(false);

    // Draft state
    const draftIdRef = useRef(draftId);
    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
    const [hasChanges, setHasChanges] = useState(false);
    const saveTimerRef = useRef(null);
    const [, forceUpdate] = useState(0);

    // Expose saveTimerRef to parent so it can cancel pending auto-saves
    useEffect(() => {
        if (editorStateRef) {
            editorStateRef.current.saveTimerRef = saveTimerRef;
        }
    }, [editorStateRef]);

    const {session, user} = useAuth();

    const queryClient = useQueryClient();
    const userId = user?.userData?.[0]?.id || null;

    // Keep draftIdRef in sync
    useEffect(() => {
        draftIdRef.current = draftId;
    }, [draftId]);

    // Tick the "saved X ago" display every 30s
    useEffect(() => {
        if (!lastSavedAt) return;
        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
        return () => clearInterval(interval);
    }, [lastSavedAt]);

    const invalidateCreatedJournalQueries = useCallback(async() => {
        const invalidations = [
            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
        ];

        if(userId){
            invalidations.push(
                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
            );
        }

        await Promise.allSettled(invalidations);
    }, [queryClient, userId]);

    const handleSaveDraft = useCallback(async(showFeedback = true) => {
        if (!editorState || !session?.access_token) return;
        if (showFeedback) setSaveStatus('saving');

        try {
            const result = await saveDraft(session.access_token, {
                content: editorState,
                title: title || '',
                draftId: draftIdRef.current || null,
                prompt_id: promptId || null,
            });

            if (result?.id && !draftIdRef.current) {
                draftIdRef.current = result.id;
                if (onDraftIdCreated) onDraftIdCreated(result.id);
            }

            setHasChanges(false);
            setSaveStatus('saved');
            setLastSavedAt(new Date());
            if (editorStateRef) {
                editorStateRef.current = { ...editorStateRef.current, hasChanges: false };
            }
            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
        } catch (error) {
            console.error('Failed to save draft:', error);
            setSaveStatus('unsaved');
        }
    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);

    // Auto-save every 30 seconds when there are changes
    useEffect(() => {
        if (!hasChanges || !editorState) return;

        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
        saveTimerRef.current = setTimeout(() => {
            handleSaveDraft(false);
        }, 30000);

        return () => {
            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
        };
    }, [editorState, hasChanges, handleSaveDraft]);

    const handleClickPublish = async(e, title) => {
        e.stopPropagation();
        setIsSending(true);

        try {
            // If we have a draft, publish it
            if (draftIdRef.current) {
                // Save latest content first
                await saveDraft(session.access_token, {
                    content: editorState,
                    title: title || '',
                    draftId: draftIdRef.current,
                });

                await publishDraft(session.access_token, draftIdRef.current);
            } else {
                // Direct publish (no draft exists) — use existing save-journal flow
                const formdata = new FormData();
                if(title && editorState){
                    formdata.append('title', title);
                    formdata.append('content', editorState);
                }
                if(promptId){
                    formdata.append('prompt_id', promptId);
                }
                await saveJournal(session?.access_token, formdata);
            }

            await invalidateCreatedJournalQueries();
            setHasContent(false);
            onCloseOnSave();
            addUploadImagesPath([]);
        } catch (error) {
            console.error("Error publishing journal:", error);
        } finally {
            setIsSending(false);
        }
    }

    const onchange = useCallback((state) => {
        const jsonb = JSON.stringify(state.toJSON());
        setEditorState(jsonb)
        setHasChanges(true);
        if (saveStatus === 'saved') setSaveStatus('unsaved');

        state.read(() => {
            const root = $getRoot();

            const children = root.getChildren();

            const hasEnoughParagraphNodes = children.length > 1
            const hasParargraphSize = children[0]?.__size > 0

            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
            setHasContent(hasContent);

            // Calculate word count
            const text = root.getTextContent().trim();
            const words = text ? text.split(/\s+/).length : 0;
            setWordCount(words);

            // Expose state to parent via ref
            if (editorStateRef) {
                editorStateRef.current = { ...editorStateRef.current, hasChanges: true, hasContent, editorState: jsonb, title };
            }
        })
    }, [setWordCount, saveStatus])

    const renderSaveStatus = () => {
        if (!saveStatus) return null;

        let statusText = '';
        let statusClass = 'editor-save-status';

        switch (saveStatus) {
            case 'saving':
                statusText = 'Saving...';
                statusClass += ' editor-save-status--saving';
                break;
            case 'saved':
                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
                statusClass += ' editor-save-status--saved';
                break;
            case 'unsaved':
                statusText = 'Unsaved changes';
                statusClass += ' editor-save-status--unsaved';
                break;
            default:
                return null;
        }

        return <span className={statusClass}>{statusText}</span>;
    };

    return(
        <>
        {/* Bar loader directly under toolbar */}
        <div className="editor-loader-wrapper">
            {isSending && (
                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
            )}
        </div>

        {/* Editor content area */}
        <div className="editor-shell">
            <RichTextPlugin
            contentEditable={
            <ContentEditable
            className="editor-input"
            aria-placeholder="Write your thoughts here..."
            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
            }
            ErrorBoundary={LexicalErrorBoundary}
            />

            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
            <MentionPlugin/>
            <HistoryPlugin/>
            <OnChangePlugin onChange={onchange}/>
            <ListPlugin/>
            <CheckListPlugin/>
            <HorizontalRulePlugin/>
            <LinkPlugin validateUrl={(url) => {
                try { return Boolean(new URL(url)); } catch { return false; }
            }}/>
            <AutoLinkPlugin/>
            <CodeHighlightPlugin/>
            <MarkdownShortcutPlugin transformers={TRANSFORMERS}/>
            <FloatingLinkEditor/>
            <FloatingSelectionToolbar/>
            <PasteImagePlugin addUploadedImagePath={addUploadImagesPath} token={session?.access_token}/>

        </div>

        {/* Footer: word count + save status + buttons */}
        <div className='editor-footer'>
            <div className="editor-footer-left">
                <span className="editor-word-count">
                    {wordCount} {wordCount === 1 ? 'word' : 'words'}
                </span>
                {renderSaveStatus()}
            </div>
            <div className="editor-footer-actions">
                <button
                    disabled={!hasContent || isSending}
                    onClick={() => handleSaveDraft(true)}
                    className={hasContent && !isSending ? 'editor-draft-bttn' : 'editor-draft-bttn-disabled'}
                >
                    Save Draft
                </button>
                <button
                    disabled={!title || !hasContent || isSending}
                    onClick={(e) => handleClickPublish(e, title)}
                    className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}
                >
                    Publish
                </button>
            </div>
        </div>
        </>
    )
}

export default EditorInner;

import { useCallback, useEffect, useRef, useState } from "react";

import {
  FORMAT_TEXT_COMMAND,
  FORMAT_ELEMENT_COMMAND,
  UNDO_COMMAND,
  REDO_COMMAND,
  CAN_UNDO_COMMAND,
  CAN_REDO_COMMAND,
  COMMAND_PRIORITY_LOW,
  $getSelection,
  $isRangeSelection,
  $createParagraphNode,
} from "lexical";

import { $createHeadingNode, $isHeadingNode, $createQuoteNode, $isQuoteNode } from "@lexical/rich-text";
import { $getSelectionStyleValueForProperty, $patchStyleText, $setBlocksType } from "@lexical/selection";
import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
import { $isListNode, INSERT_UNORDERED_LIST_COMMAND, INSERT_ORDERED_LIST_COMMAND, INSERT_CHECK_LIST_COMMAND, REMOVE_LIST_COMMAND } from "@lexical/list";
import { $isCodeNode, $createCodeNode } from "@lexical/code";
import { $isLinkNode, TOGGLE_LINK_COMMAND, $toggleLink } from "@lexical/link";
import { INSERT_HORIZONTAL_RULE_COMMAND } from "@lexical/react/LexicalHorizontalRuleNode";
import { INSERT_IMAGE_COMMAND } from "./nodes/ImageNode";
import { saveJournalImage } from "../../../../API/Api";
import { useAuth } from "../../../Context/useAuth";

const DEFAULT_ACTIVE_STATES = {
    bold: false,
    italic: false,
    underline: false,
    strikethrough: false,
    inlineCode: false,
    heading: null,
    quote: false,
    alignment: 'left',
    textColor: '',
    highlightColor: '',
    listType: null, // 'bullet' | 'number' | 'check' | null
    isCodeBlock: false,
    isLink: false,
    canUndo: false,
    canRedo: false,
};

const ToolBar = ({addUploadedImagePath}) =>{
    const [editor] = useLexicalComposerContext();
    const {session} = useAuth();
    const colorPickerRef = useRef(null);

    // Active state tracking
    const [activeStates, setActiveStates] = useState(DEFAULT_ACTIVE_STATES);

    const [showTextColorPicker, setShowTextColorPicker] = useState(false);
    const [showHighlightColorPicker, setShowHighlightColorPicker] = useState(false);

    const COLOR_PALETTE = [
        { label: 'Default', value: null },
        { label: 'Black', value: '#000000' },
        { label: 'Dark Gray', value: '#4d4d4d' },
        { label: 'Gray', value: '#888888' },
        { label: 'Light Gray', value: '#bfbfbf' },
        { label: 'Red', value: '#f44336' },
        { label: 'Pink', value: '#e91e63' },
        { label: 'Purple', value: '#9c27b0' },
        { label: 'Deep Purple', value: '#673ab7' },
        { label: 'Indigo', value: '#3f51b5' },
        { label: 'Blue', value: '#2196f3' },
        { label: 'Light Blue', value: '#03a9f4' },
        { label: 'Cyan', value: '#00bcd4' },
        { label: 'Teal', value: '#009688' },
        { label: 'Green', value: '#4caf50' },
        { label: 'Light Green', value: '#8bc34a' },
        { label: 'Lime', value: '#cddc39' },
        { label: 'Yellow', value: '#ffeb3b' },
        { label: 'Amber', value: '#ffc107' },
        { label: 'Orange', value: '#ff9800' },
        { label: 'Deep Orange', value: '#ff5722' },
        { label: 'Brown', value: '#795548' },
        { label: 'Blue Gray', value: '#607d8b' },
    ];

    const toCompactRgb = (value) => {
        if (!value) return '';
        return value.toLowerCase().replace(/\s+/g, '');
    };

    const normalizeColor = (value) => {
        if (!value) return '';
        const trimmed = value.trim().toLowerCase();
        if (!trimmed.startsWith('#')) {
            return toCompactRgb(trimmed);
        }

        let hex = trimmed.slice(1);
        if (hex.length === 3) {
            hex = hex.split('').map((char) => `${char}${char}`).join('');
        }
        if (hex.length !== 6) {
            return trimmed;
        }

        const r = parseInt(hex.slice(0, 2), 16);
        const g = parseInt(hex.slice(2, 4), 16);
        const b = parseInt(hex.slice(4, 6), 16);

        return `rgb(${r},${g},${b})`;
    };

    const isPaletteColorActive = (activeValue, paletteValue) => {
        const normalizedActive = normalizeColor(activeValue);
        if (!paletteValue) {
            return !normalizedActive;
        }
        return normalizedActive === normalizeColor(paletteValue);
    };

    // Register undo/redo command listeners
    useEffect(() => {
        const unregisterUndo = editor.registerCommand(
            CAN_UNDO_COMMAND,
            (payload) => {
                setActiveStates((prev) => ({ ...prev, canUndo: payload }));
                return false;
            },
            COMMAND_PRIORITY_LOW,
        );
        const unregisterRedo = editor.registerCommand(
            CAN_REDO_COMMAND,
            (payload) => {
                setActiveStates((prev) => ({ ...prev, canRedo: payload }));
                return false;
            },
            COMMAND_PRIORITY_LOW,
        );
        return () => {
            unregisterUndo();
            unregisterRedo();
        };
    }, [editor]);

    // Register update listener for active state detection
    useEffect(() => {
        return editor.registerUpdateListener(({ editorState }) => {
            editorState.read(() => {
                const selection = $getSelection();
                if (!$isRangeSelection(selection)) {
                    setActiveStates((prev) => ({
                        ...DEFAULT_ACTIVE_STATES,
                        canUndo: prev.canUndo,
                        canRedo: prev.canRedo,
                    }));
                    return;
                }

                const bold = selection.hasFormat('bold');
                const italic = selection.hasFormat('italic');
                const underline = selection.hasFormat('underline');
                const strikethrough = selection.hasFormat('strikethrough');
                const inlineCode = selection.hasFormat('code');

                const anchorNode = selection.anchor.getNode();
                const parent = anchorNode.getParent();

                let element;
                try {
                    element = anchorNode.getKey() === 'root'
                        ? anchorNode
                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
                } catch {
                    element = null;
                }

                let heading = null;
                let quote = false;
                let alignment = 'left';
                let listType = null;
                let isCodeBlock = false;
                let isLink = false;

                if (element) {
                    if ($isHeadingNode(element)) {
                        heading = element.getTag();
                    }
                    if ($isQuoteNode(element)) {
                        quote = true;
                    }
                    if ($isListNode(element)) {
                        const type = element.getListType();
                        listType = type === 'bullet' ? 'bullet' : type === 'number' ? 'number' : type === 'check' ? 'check' : null;
                    }
                    if ($isCodeNode(element)) {
                        isCodeBlock = true;
                    }
                    const formatType = element.getFormatType?.();
                    if (formatType) {
                        alignment = formatType;
                    }
                }

                // Check for list type on parent (listitem → list)
                if (!listType && parent) {
                    const grandParent = parent.getParent?.();
                    if (grandParent && $isListNode(grandParent)) {
                        const type = grandParent.getListType();
                        listType = type === 'bullet' ? 'bullet' : type === 'number' ? 'number' : type === 'check' ? 'check' : null;
                    }
                }

                // Check for link
                if ($isLinkNode(parent)) {
                    isLink = true;
                } else if ($isLinkNode(anchorNode)) {
                    isLink = true;
                }

                const textColor = $getSelectionStyleValueForProperty(selection, 'color', '');
                const highlightColor = $getSelectionStyleValueForProperty(selection, 'background-color', '');

                setActiveStates((prev) => ({
                    bold,
                    italic,
                    underline,
                    strikethrough,
                    inlineCode,
                    heading,
                    quote,
                    alignment,
                    textColor,
                    highlightColor,
                    listType,
                    isCodeBlock,
                    isLink,
                    canUndo: prev.canUndo,
                    canRedo: prev.canRedo,
                }));
            });
        });
    }, [editor]);

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (!colorPickerRef.current) return;
            if (!colorPickerRef.current.contains(event.target)) {
                setShowTextColorPicker(false);
                setShowHighlightColorPicker(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);


    const applyTextFormat = (format) => {
        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
    }

    const applyTextStyle = useCallback((styles) => {
        const sanitizedStyles = Object.fromEntries(
            Object.entries(styles).map(([key, value]) => [key, value ?? ''])
        );
        editor.update(() => {
            const selection = $getSelection();
            if ($isRangeSelection(selection)) {
                $patchStyleText(selection, sanitizedStyles);
            }
        });
    }, [editor]);

    //heading node (H1, H2, H3)
    const setHeading = (tag) => {
        editor.update(() => {
            const selection = $getSelection();
            if ($isRangeSelection(selection)) {
                const anchorNode = selection.anchor.getNode();

                let element;
                try {
                    element = anchorNode.getKey() === 'root'
                        ? anchorNode
                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
                } catch (e) {
                    console.error('Could not get top level element:', e);
                    return;
                }

                if (!element) return;

                const type = typeof element.getType === 'function' ? element.getType() : null;

                if (type && type !== "paragraph" && type !== "heading" && type !== "root") {
                    return;
                }

                const isActive = $isHeadingNode(element) && element.getTag() === tag;

                $setBlocksType(selection, () =>
                    isActive ? $createParagraphNode() : $createHeadingNode(tag)
                );
            }
        })
    }

    //align element
    const setAlignment = (value) => {
        editor.dispatchCommand(FORMAT_ELEMENT_COMMAND, value);
    }

    //quote block (toggle)
    const setQuote = () => {
        editor.update(() => {
            const selection = $getSelection();
            if ($isRangeSelection(selection)) {
                const anchorNode = selection.anchor.getNode();

                let element;
                try {
                    element = anchorNode.getKey() === 'root'
                        ? anchorNode
                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
                } catch (e) {
                    console.error('Could not get top level element:', e);
                    return;
                }

                if (!element) return;

                const type = typeof element.getType === 'function' ? element.getType() : null;
                if (type && type !== "paragraph" && type !== "heading" && type !== "quote" && type !== "root") {
                    return;
                }

                const isActive = $isQuoteNode(element);

                $setBlocksType(selection, () =>
                    isActive ? $createParagraphNode() : $createQuoteNode()
                );
            }
        })
    }

    // List commands
    const toggleList = (type) => {
        if (activeStates.listType === type) {
            editor.dispatchCommand(REMOVE_LIST_COMMAND, undefined);
        } else {
            switch (type) {
                case 'bullet':
                    editor.dispatchCommand(INSERT_UNORDERED_LIST_COMMAND, undefined);
                    break;
                case 'number':
                    editor.dispatchCommand(INSERT_ORDERED_LIST_COMMAND, undefined);
                    break;
                case 'check':
                    editor.dispatchCommand(INSERT_CHECK_LIST_COMMAND, undefined);
                    break;
            }
        }
    };

    // Code block toggle
    const toggleCodeBlock = () => {
        editor.update(() => {
            const selection = $getSelection();
            if ($isRangeSelection(selection)) {
                if (activeStates.isCodeBlock) {
                    $setBlocksType(selection, () => $createParagraphNode());
                } else {
                    $setBlocksType(selection, () => $createCodeNode());
                }
            }
        });
    };

    // Link toggle
    const toggleLink = () => {
        editor.update(() => {
            const selection = $getSelection();
            if (!$isRangeSelection(selection)) return;
            if (activeStates.isLink) {
                $toggleLink(null);
            } else {
                $toggleLink('https://');
            }
        });
    };

    //insert image
    const insertImageFromFile = async() => {

        const handleOnChange = async(e) => {
            const filedata = e.target.files?.[0];
            if(!filedata) return;

            const blobUrl = URL.createObjectURL(filedata);

            editor.dispatchCommand(INSERT_IMAGE_COMMAND, {
                src: blobUrl,
                width: 500,
                height: 500,
                loading: true,
            })

            const formdata = new FormData();
            formdata.append('image', filedata);

            try {
                const data_url = await saveJournalImage(session?.access_token, formdata);
                if(!data_url){
                    return;
                }

                const filePath = data_url.img_url.split('/journal-images/').pop();
                if (filePath && addUploadedImagePath) {
                    addUploadedImagePath(filePath);
                }

                editor.update(() => {
                    const root = editor.getEditorState()._nodeMap;
                    for (const [, node] of root) {
                        if (node.__type === 'image' && node.__src === blobUrl) {
                            node.getWritable().__src = data_url.img_url;
                            node.getWritable().__loading = false;
                            break;
                        }
                    }
                });

                URL.revokeObjectURL(blobUrl);
            } catch (err) {
                console.error('Image upload failed:', err);
            }
        }

        const input = document.createElement('input');
        input.type = 'file'
        input.accept = 'image/*';
        input.onchange = (e) => {handleOnChange(e)}

        input.click();
    };

    // Helper to get class name based on active state
