                node.getWritable().__src = data_url.img_url;
                node.getWritable().__loading = false;
                break;
            }
        }
    });

    URL.revokeObjectURL(blobUrl);
} catch (err) {
    console.error('Image upload failed:', err);
    URL.revokeObjectURL(blobUrl);

