/* ── Mobile responsive (overrides only) ── */
@media (max-width: 640px) {
    .editor-parent-container {
        z-index: 132;
    }
    .editor-container {
        width: 95%;
        height: 95%;
        padding: 0.75rem;
        border-radius: 12px;
    }
    /* Mobile toolbar: horizontal scroll with visible thin scrollbar */
    .toolbar {
        flex-wrap: nowrap;
        overflow-x: auto;
        -webkit-overflow-scrolling: touch;
        scrollbar-width: thin;
        min-width: 0;
    }
    .toolbar .group,
    .toolbar .toolbar-bttns,
    .toolbar .is-active {
        flex-shrink: 0;
    }
    .toolbar::-webkit-scrollbar {
        height: 3px;
    }
    .toolbar::-webkit-scrollbar-thumb {
        background: var(--editor-border);
        border-radius: 3px;
    }
    .toolbar-wrapper {
        position: relative;
    }
    .toolbar-wrapper::after {
        content: '';
        position: absolute;
        top: 0;
        right: 0;
        bottom: 0;
        width: 24px;
        background: linear-gradient(to right, transparent, var(--editor-bg, var(--bg-elevated)));
        pointer-events: none;
        z-index: 6;
    }
    .toolbar-bttns,
    .is-active {
        padding: 0.55rem;
        min-width: 36px;
        min-height: 36px;
    }
    .toolbar-bttns svg,
    .is-active svg {
        width: 18px;
        height: 18px;
    }
    .toolbar-divider {
        margin: 0 4px;
        height: 16px;
    }
    .color-popover {
        bottom: calc(100% + 6px);
        top: auto;
    }
    .content-title-input {
        font-size: 1.35rem;
    }
    .editor-save-bttn {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-save-bttn-disabled {
        padding: 0.35rem 0.9rem;
        font-size: 0.85rem;
    }
    .editor-draft-bttn {
        padding: 0.35rem 0.75rem;
        font-size: 0.8rem;
    }
    .editor-draft-bttn-disabled {
        padding: 0.35rem 0.75rem;
        font-size: 0.8rem;
    }
    .editor-footer-actions {
        gap: 0.35rem;
    }
    .editor-close-confirm-overlay {
        border-radius: 12px;
    }
    .editor-close-confirm-card {
        padding: 1.25rem 1.5rem;
        max-width: 280px;
    }
}

